private List<FolderTreeNodeVo> buildFolderTree(String spaceId) {
    List<TreeNode<SpaceNodeVo>> fullTree = spaceNodeQueryManager.getSpaceNodeTree(spaceId);
    return filterFolders(fullTree);
}

private List<FolderTreeNodeVo> filterFolders(List<TreeNode<SpaceNodeVo>> nodes) {
    if (nodes == null || nodes.isEmpty()) {
        return List.of();
    }
    List<FolderTreeNodeVo> result = new ArrayList<>();
    for (TreeNode<SpaceNodeVo> node : nodes) {
        SpaceNodeVo data = node.getData();
        if (Objects.equals(data.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
            result.add(FolderTreeNodeVo.builder()
                    .id(data.getId())
                    .name(data.getName())
                    .children(filterFolders(node.getChildren()))
                    .build());
        } else {
            result.addAll(filterFolders(node.getChildren()));
        }
    }
    return result;
}
